from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a fluent description from a list of triples."""
    if not triples:
        return ""
    clauses = []
    for t in triples:
        s, p, o = t.subject, t.predicate, t.object
        # Basic lexicalisation per predicate
        if p == "birthDate":
            clause = f"{s} was born on {o}"
        elif p == "birthPlace":
            clause = f"{s} was born in {o}"
        elif p == "deathDate":
            clause = f"{s} died on {o}"
        elif p == "deathPlace":
            clause = f"{s} died in {o}"
        elif p == "nationality":
            clause = f"{s} was a {o} astronaut"
        elif p == "occupation":
            clause = f"{s}'s occupation was {o}"
        elif p == "mission":
            clause = f"{s} flew on the {o} mission"
        elif p == "timeInSpace":
            clause = f"{s} spent {o} minutes in space"
        elif p == "selectedByNasa":
            clause = f"{s} was selected by NASA in {o}"
        elif p == "status":
            clause = f"{s} is currently {o}"
        elif p == "title":
            clause = f"{s} held the title of {o}"
        elif p in ("award", "awards"):
            clause = f"{s} received the {o} award"
        elif p == "ribbonAward":
            clause = f"{s} received the {o} ribbon"
        elif p == "commander":
            clause = f"The commander of {s} was {o}"
        elif p == "backupPilot":
            clause = f"The backup pilot of {s} was {o}"
        elif p == "crewMembers":
            clause = f"{s} had crew member {o}"
        elif p == "operator":
            clause = f"{s} was operated by {o}"
        elif p == "alternativeName":
            clause = f"{s} is also known as {o}"
        elif p == "almaMater":
            clause = f"{s} studied at {o}"
        elif p == "dateOfRetirement":
            clause = f"{s} retired in {o}"
        elif p == "servedAsChiefOfTheAstronautOfficeIn":
            clause = f"{s} served as Chief of the Astronaut Office in {o}"
        elif p == "representative":
            clause = f"{s} is represented by {o}"
        elif p == "cosparId":
            clause = f"The COSPAR ID of {s} is {o}"
        elif p == "utcOffset":
            clause = f"{s} has a UTC offset of {o}"
        else:
            clause = f"{s} {p} {o}"
        clauses.append(clause)
    # Join clauses into a single fluent sentence
    sentence = "; ".join(clauses) + "."
    return sentence

# EVOLVE-BLOCK-END

